//! PyTorch-oracle parity tests.
//!
//! Loads fixtures generated by `scripts/generate_pytorch_fixtures.py` and
//! compares flame-core's op output against PyTorch's, element-wise. PyTorch
//! is the source of truth — no circular comparisons.
//!
//! Run:
//!   PYTORCH_FIXTURES=tests/pytorch_fixtures/ cargo test --release --test pytorch_parity
//!
//! Perf table (prints, does not gate):
//!   PYTORCH_FIXTURES=tests/pytorch_fixtures/ \
//!     cargo test --release --test pytorch_parity perf_comparison -- --ignored --nocapture
//!
//! ## Adaptation notes (from the original drop)
//!
//! The original `pytorch_parity.rs` was authored against a generic PyTorch-
//! style op surface. flame-core diverges in a few places that matter here:
//!
//!   - Op results are `flame_core::Result<Tensor>`, not `anyhow::Result`.
//!   - Comparison ops (`gt`/`ge`/`lt`/`le`/`eq`/`ne`) return BF16 0.0/1.0
//!     sentinels, not bool/u8 (see CONVENTIONS.md). PyTorch returns bool.
//!     We cast PyTorch's output to f32 0/1 and compare bit-for-bit.
//!   - `Tensor::eq` / `Tensor::ne` (not `eq_tensor`/`ne_tensor`).
//!   - No `Tensor::linear` / `Tensor::conv2d` methods in flame-core —
//!     those call sites use standalone `ops::fused_inference` functions
//!     or `conv::Conv2d`. For the generic parity here we use the
//!     decomposed matmul+bias form; conv2d is `#[ignore]`d pending a
//!     dedicated conv parity test.
//!   - `swiglu_fused_bf16(gate, up)` takes two tensors; the fixture saves
//!     a packed `[B, N, 2D]` input, so we narrow it in half first.
//!   - `fused_rms_norm` lives at `ops::fused_inference::fused_rms_norm`.

#![cfg(all(feature = "cuda", feature = "bf16_u16"))]

use flame_core::{Error, Result, Tensor};
use std::collections::HashMap;
use std::fs;
use std::path::{Path, PathBuf};
use std::time::Instant;

// ---------------------------------------------------------------------------
// Test infrastructure
// ---------------------------------------------------------------------------

fn fixtures_dir() -> PathBuf {
    PathBuf::from(
        std::env::var("PYTORCH_FIXTURES").unwrap_or_else(|_| "tests/pytorch_fixtures".to_string()),
    )
}

fn skip_if_no_fixtures() -> bool {
    let dir = fixtures_dir();
    if !dir.exists() {
        eprintln!(
            "SKIP: fixtures dir {:?} not found. Run scripts/generate_pytorch_fixtures.py first.",
            dir
        );
        true
    } else {
        false
    }
}

/// Load a safetensors fixture file into GPU tensors. Routes through
/// `flame_core::serialization::load_file`, which is the same path used by
/// inference-flame to load model weights — so we test the same code path
/// our production model loads go through.
fn load_fixture(path: &Path) -> HashMap<String, Tensor> {
    let device = flame_core::global_cuda_device();
    flame_core::serialization::load_file(path, &device)
        .unwrap_or_else(|e| panic!("load_file {:?} failed: {:?}", path, e))
}

/// BF16 bit-exact length-match. Returns the mismatch count (0 = bit-exact).
fn count_bf16_mismatches(got: &Tensor, expected: &Tensor) -> usize {
    let got_bits = got.to_vec_bf16().expect("to_vec_bf16 on got");
    let exp_bits = expected.to_vec_bf16().expect("to_vec_bf16 on expected");
    assert_eq!(
        got_bits.len(),
        exp_bits.len(),
        "length mismatch: got {} vs expected {}",
        got_bits.len(),
        exp_bits.len()
    );
    got_bits
        .iter()
        .zip(exp_bits.iter())
        .filter(|(a, b)| a != b)
        .count()
}

fn cos_sim_f32(got: &Tensor, expected: &Tensor) -> f64 {
    let gf = got.to_vec_f32().expect("to_vec_f32 on got");
    let ef = expected.to_vec_f32().expect("to_vec_f32 on expected");
    assert_eq!(gf.len(), ef.len(), "cos_sim length mismatch");
    let dot: f64 = gf
        .iter()
        .zip(ef.iter())
        .map(|(a, b)| *a as f64 * *b as f64)
        .sum();
    let na: f64 = gf.iter().map(|x| (*x as f64).powi(2)).sum::<f64>().sqrt();
    let nb: f64 = ef.iter().map(|x| (*x as f64).powi(2)).sum::<f64>().sqrt();
    if na == 0.0 || nb == 0.0 {
        0.0
    } else {
        dot / (na * nb)
    }
}

fn max_abs_diff(got: &Tensor, expected: &Tensor) -> f32 {
    let gf = got.to_vec_f32().expect("to_vec_f32 on got");
    let ef = expected.to_vec_f32().expect("to_vec_f32 on expected");
    gf.iter()
        .zip(ef.iter())
        .map(|(a, b)| (a - b).abs())
        .fold(0.0f32, f32::max)
}

fn assert_cos_sim(name: &str, got: &Tensor, expected: &Tensor, threshold: f64) {
    let cos = cos_sim_f32(got, expected);
    assert!(
        cos >= threshold,
        "{name}: cos_sim = {cos:.8} < threshold {threshold} (max_abs_diff {:.4e})",
        max_abs_diff(got, expected)
    );
}

fn discover_fixtures(dir: &Path) -> Vec<PathBuf> {
    if !dir.exists() {
        return vec![];
    }
    let mut files: Vec<PathBuf> = fs::read_dir(dir)
        .unwrap_or_else(|_| panic!("Failed to read dir {:?}", dir))
        .filter_map(|e| e.ok())
        .map(|e| e.path())
        .filter(|p| p.extension().map_or(false, |ext| ext == "safetensors"))
        .collect();
    files.sort();
    files
}

// ---------------------------------------------------------------------------
// Section 1: Unary op parity
// ---------------------------------------------------------------------------

fn run_unary_test(op_name: &str, op_fn: fn(&Tensor) -> Result<Tensor>) {
    if skip_if_no_fixtures() {
        return;
    }

    let dir = fixtures_dir().join("unary").join(op_name);
    let fixtures = discover_fixtures(&dir);
    assert!(
        !fixtures.is_empty(),
        "No fixtures found for unary/{op_name} at {dir:?}"
    );

    for fixture_path in &fixtures {
        let stem = fixture_path.file_stem().unwrap().to_str().unwrap();
        let tensors = load_fixture(fixture_path);
        let input = tensors.get("input").expect("missing 'input' in fixture");
        let expected = tensors.get("output").expect("missing 'output' in fixture");

        let got = op_fn(input).unwrap_or_else(|e| panic!("{op_name}/{stem}: op failed: {e:?}"));

        let mismatches = count_bf16_mismatches(&got, expected);
        if mismatches == 0 {
            println!("  {op_name}/{stem}: bit-exact");
        } else {
            let cos = cos_sim_f32(&got, expected);
            let mad = max_abs_diff(&got, expected);
            println!(
                "  {op_name}/{stem}: cos_sim={cos:.8} max_abs_diff={mad:.4e} ({mismatches} bf16 bits differ)"
            );
            assert!(
                cos >= 0.9999,
                "{op_name}/{stem}: cos_sim {cos:.8} < 0.9999"
            );
        }
    }
}

