fn run_binary_test(op_name: &str, op_fn: fn(&Tensor, &Tensor) -> Result<Tensor>) {
    if skip_if_no_fixtures() {
        return;
    }

    let dir = fixtures_dir().join("binary").join(op_name);
    let fixtures = discover_fixtures(&dir);
    assert!(!fixtures.is_empty(), "No fixtures for binary/{op_name}");

    for fixture_path in &fixtures {
        let stem = fixture_path.file_stem().unwrap().to_str().unwrap();
        let tensors = load_fixture(fixture_path);
        let a = tensors.get("input_a").expect("missing 'input_a'");
        let b = tensors.get("input_b").expect("missing 'input_b'");
        let expected = tensors.get("output").expect("missing 'output'");

        let got = op_fn(a, b).unwrap_or_else(|e| panic!("{op_name}/{stem}: op failed: {e:?}"));

        let mismatches = count_bf16_mismatches(&got, expected);
        if mismatches == 0 {
            println!("  {op_name}/{stem}: bit-exact");
        } else {
            let cos = cos_sim_f32(&got, expected);
            let mad = max_abs_diff(&got, expected);
            println!(
                "  {op_name}/{stem}: cos_sim={cos:.8} max_abs_diff={mad:.4e} ({mismatches} bf16 bits differ)"
            );
            assert!(
                cos >= 0.9999,
                "{op_name}/{stem}: cos_sim {cos:.8} < 0.9999"
            );
        }
    }
}

