// ---------------------------------------------------------------------------
// Section 6: Matmul / Linear parity
// ---------------------------------------------------------------------------
//
// PyTorch's `F.linear(x, w, b)` = `x @ w.T + b`. flame-core has no
// `Tensor::linear` method; the inference hot path uses
// `ops::fused_inference::fused_linear3d_native` which expects weight in
// PyTorch-native `[out, in]` layout. For generic 2D matmul we use
// `Tensor::matmul` against the weight's transpose, then add bias.

#[test]
fn parity_matmul_linear() {
    if skip_if_no_fixtures() { return; }
    let dir = fixtures_dir().join("matmul");
    for fixture_path in discover_fixtures(&dir) {
        let stem = fixture_path.file_stem().unwrap().to_str().unwrap();
        if stem.ends_with("_nobias") { continue; }

        let tensors = load_fixture(&fixture_path);
        let input = tensors.get("input").unwrap();
        let weight = tensors.get("weight").unwrap();
        let bias = tensors.get("bias").unwrap();
        let expected = tensors.get("output").unwrap();

        let w_t = weight.transpose().unwrap();
        let logits = input.matmul(&w_t).unwrap();
        let got = logits.add(bias).unwrap();
        assert_cos_sim(&format!("linear/{stem}"), &got, expected, 0.999);
        println!("  linear/{stem}: ok");
    }
}

