// ---------------------------------------------------------------------------
// Section 8: Fused-op parity (where flame-core should be faster than PyTorch)
// ---------------------------------------------------------------------------

#[test]
fn parity_fused_swiglu() {
    if skip_if_no_fixtures() { return; }
    let dir = fixtures_dir().join("fused");
    for fixture_path in discover_fixtures(&dir) {
        let stem = fixture_path.file_stem().unwrap().to_str().unwrap();
        if !stem.starts_with("swiglu_") { continue; }

        let tensors = load_fixture(&fixture_path);
        let gate_up = tensors.get("input").unwrap();
        let expected = tensors.get("output").unwrap();

        // flame-core's swiglu takes (gate, up) as separate tensors.
        // Fixture packs them as [B, N, 2D] on the last dim.
        let dims = gate_up.shape().dims();
        let last = *dims.last().expect("swiglu: empty shape");
        assert_eq!(last % 2, 0, "swiglu/{stem}: last dim {last} not even");
        let half = last / 2;
        let last_axis = dims.len() - 1;
        let gate = gate_up.narrow(last_axis, 0, half).unwrap();
        let up = gate_up.narrow(last_axis, half, half).unwrap();
        let got = flame_core::bf16_ops::swiglu_fused_bf16(&gate, &up).unwrap();
        assert_cos_sim(&format!("swiglu/{stem}"), &got, expected, 0.9999);
        println!("  swiglu/{stem}: ok");
    }
}

