// ---------------------------------------------------------------------------
// Section 10: Performance comparison
// ---------------------------------------------------------------------------
//
// Run explicitly: `cargo test --release --test pytorch_parity perf_comparison
// -- --ignored --nocapture`. Does NOT assert on timing — just reports.

fn device_sync() -> Result<()> {
    let device = flame_core::global_cuda_device();
    device
        .synchronize()
        .map_err(|e| Error::Cuda(format!("synchronize: {:?}", e)))
}

fn bench_flame<F: FnMut() -> Result<()>>(mut f: F, warmup: usize, iters: usize) -> f64 {
    for _ in 0..warmup {
        let _ = f();
    }
    let _ = device_sync();
    let mut times = Vec::with_capacity(iters);
    for _ in 0..iters {
        let _ = device_sync();
        let t0 = Instant::now();
        let _ = f();
        let _ = device_sync();
        times.push(t0.elapsed().as_nanos() as f64 / 1000.0);
    }
    times.sort_by(|a, b| a.partial_cmp(b).unwrap());
    times[times.len() / 2]
}

/// Try to run a flame-core equivalent for the given (op_path, shape_name)
/// entry from `timing_results.json`. Returns `None` when the op isn't
/// wired up (conv2d needs Conv2d wrapping; pattern/* needs weight
/// reconstruction infra — both deferred).
///
/// Op paths in the JSON come in two forms:
///   - "category/subop"  — unary/silu, binary/add, matmul/linear, etc.
///   - "category"        — sdpa, conv2d (no sub-op)
///
/// Fixture file layout differs by category; see `PYTORCH_PARITY_README.md`
/// or the discover calls in the per-category blocks below.
fn bench_flame_for(op_path: &str, shape_name: &str) -> Option<f64> {
    let (category, subop) = match op_path.split_once('/') {
        Some((c, o)) => (c, Some(o)),
        None => (op_path, None),
    };
    let root = fixtures_dir();

    match category {
        "unary" => {
            let op = subop?;
            let path = root.join("unary").join(op).join(format!("{shape_name}.safetensors"));
            if !path.exists() { return None; }
            let ts = load_fixture(&path);
            let x = ts.get("input")?.clone();
            let f: fn(&Tensor) -> Result<Tensor> = match op {
                "silu"    => |t| t.silu(),
                "gelu"    => |t| t.gelu(),
                "relu"    => |t| t.relu(),
                "sigmoid" => |t| t.sigmoid(),
                "tanh"    => |t| t.tanh(),
                "abs"     => |t| t.abs(),
                "neg"     => |t| t.neg(),
                "square"  => |t| t.square(),
                "exp"     => |t| t.exp(),
                "log"     => |t| t.log(),
                "sqrt"    => |t| t.sqrt(),
                "rsqrt"   => |t| t.rsqrt(),
                "recip"   => |t| t.reciprocal(),
                _ => return None,
            };
            Some(bench_flame(|| { let _ = f(&x)?; Ok(()) }, 3, 10))
        }

        "binary" => {
            let op = subop?;
            let path = root.join("binary").join(op).join(format!("{shape_name}.safetensors"));
            if !path.exists() { return None; }
            let ts = load_fixture(&path);
            let a = ts.get("input_a")?.clone();
            let b = ts.get("input_b")?.clone();
            let f: fn(&Tensor, &Tensor) -> Result<Tensor> = match op {
                "add"     => |x, y| x.add(y),
                "sub"     => |x, y| x.sub(y),
                "mul"     => |x, y| x.mul(y),
                "div"     => |x, y| x.div(y),
                "maximum" => |x, y| x.maximum(y),
                "minimum" => |x, y| x.minimum(y),
                _ => return None,
            };
            Some(bench_flame(|| { let _ = f(&a, &b)?; Ok(()) }, 3, 10))
        }

        "scalar" => {
            let op = subop?;
            let path = root.join("scalar").join(op).join(format!("{shape_name}.safetensors"));
            if !path.exists() { return None; }
            let ts = load_fixture(&path);
            let x = ts.get("input")?.clone();
            Some(match op {
                "add_scalar" => bench_flame(|| { let _ = x.add_scalar(0.5)?; Ok(()) }, 3, 10),
                "mul_scalar" => bench_flame(|| { let _ = x.mul_scalar(2.0)?; Ok(()) }, 3, 10),
                _ => return None,
            })
        }

        "comparison" => {
            let op = subop?;
            let path = root.join("comparison").join(op).join(format!("{shape_name}.safetensors"));
            if !path.exists() { return None; }
            let ts = load_fixture(&path);
            let a = ts.get("input_a")?.clone();
            let b = ts.get("input_b")?.clone();
            let f: fn(&Tensor, &Tensor) -> Result<Tensor> = match op {
                "gt" => |x, y| x.gt(y),
                "ge" => |x, y| x.ge(y),
                "lt" => |x, y| x.lt(y),
                "le" => |x, y| x.le(y),
                "eq" => |x, y| x.eq(y),
                "ne" => |x, y| x.ne(y),
                _ => return None,
            };
            Some(bench_flame(|| { let _ = f(&a, &b)?; Ok(()) }, 3, 10))
        }

        // SDPA: fixture path is `sdpa/<shape_name>.safetensors`; shape_name
        // has `_contig` or `_strided` suffix already.
        "sdpa" => {
            let path = root.join("sdpa").join(format!("{shape_name}.safetensors"));
            if !path.exists() { return None; }
            let ts = load_fixture(&path);
            let q = ts.get("q")?.clone();
            let k = ts.get("k")?.clone();
            let v = ts.get("v")?.clone();
            Some(bench_flame(
                || { let _ = flame_core::sdpa::forward(&q, &k, &v, None)?; Ok(()) },
                3, 10,
            ))
        }

        // Matmul/Linear: fixture path is `matmul/<shape_name>.safetensors`;
        // `_nobias` variants are matmul without the bias add.
        "matmul" => {
            let op = subop?;
            let path = root.join("matmul").join(format!("{shape_name}.safetensors"));
            if !path.exists() { return None; }
            let ts = load_fixture(&path);
            let input = ts.get("input")?.clone();
            let weight = ts.get("weight")?.clone();
            match op {
                "linear" => {
                    let bias = ts.get("bias")?.clone();
                    let w_t = weight.transpose().ok()?;
                    Some(bench_flame(
                        || {
                            let logits = input.matmul(&w_t)?;
                            let _ = logits.add(&bias)?;
                            Ok(())
                        },
                        3, 10,
                    ))
                }
                "mm" => {
                    let w_t = weight.transpose().ok()?;
                    Some(bench_flame(
                        || { let _ = input.matmul(&w_t)?; Ok(()) },
                        3, 10,
                    ))
                }
                _ => None,
            }
        }

        // Fused: fixture path is `fused/<sub>_<shape>.safetensors` (e.g.
        // `swiglu_klein_hidden`). Timing entry's shape_name is just
        // `<shape>` (`klein_hidden`), so we prepend `<sub>_` here.
        "fused" => {
            let op = subop?;
            let path = root.join("fused").join(format!("{op}_{shape_name}.safetensors"));
            if !path.exists() { return None; }
            let ts = load_fixture(&path);
            match op {
                "swiglu" => {
                    let gate_up = ts.get("input")?.clone();
                    let dims = gate_up.shape().dims().to_vec();
                    let last_axis = dims.len() - 1;
                    let last = dims[last_axis];
                    if last % 2 != 0 { return None; }
                    let half = last / 2;
                    let gate = gate_up.narrow(last_axis, 0, half).ok()?;
                    let up = gate_up.narrow(last_axis, half, half).ok()?;
                    Some(bench_flame(
                        || { let _ = flame_core::bf16_ops::swiglu_fused_bf16(&gate, &up)?; Ok(()) },
                        3, 10,
                    ))
                }
                "rmsnorm" => {
                    let input = ts.get("input")?.clone();
                    let weight = ts.get("weight")?.clone();
                    Some(bench_flame(
                        || {
                            let _ = flame_core::ops::fused_inference::fused_rms_norm(
                                &input, &weight, 1e-5,
                            )?;
                            Ok(())
                        },
                        3, 10,
                    ))
                }
                _ => None,
            }
        }

        // Pattern: fixture files are `patterns/<subop>.safetensors`.
        // Dispatch key has form `pattern/<subop>` → subop here is the
        // name after "pattern/" (e.g. `klein_attention`, `klein_mlp`).
        "pattern" => {
            let op = subop?;
            // timing_results.json subops are `klein_attention`,
            // `klein_mlp`, `dit_modulate_residual`, `klein_double_block`,
            // `permute_narrow_linear`, `sdpa_backward`. The fixture file
            // names in `patterns/` use slightly different suffixes:
            //   klein_attention       → klein_attention_path.safetensors
            //   klein_mlp             → klein_mlp_path.safetensors
            //   dit_modulate_residual → dit_modulate_residual.safetensors
            //   klein_double_block    → klein_double_block.safetensors
            let file = match op {
                "klein_attention"       => "klein_attention_path.safetensors",
                "klein_mlp"             => "klein_mlp_path.safetensors",
                "dit_modulate_residual" => "dit_modulate_residual.safetensors",
                "klein_double_block"    => "klein_double_block.safetensors",
                // permute_narrow_linear / sdpa_backward not wired.
                _ => return None,
            };
            let path = root.join("patterns").join(file);
            if !path.exists() { return None; }
            let ts = load_fixture(&path);
            Some(match op {
                "klein_attention" => bench_flame(
                    || { let _ = run_klein_attn(&ts)?; Ok(()) }, 3, 10,
                ),
                "klein_mlp" => bench_flame(
                    || { let _ = run_klein_mlp(&ts)?; Ok(()) }, 3, 10,
                ),
                "dit_modulate_residual" => bench_flame(
                    || { let _ = run_dit_modulate_residual(&ts)?; Ok(()) }, 3, 10,
                ),
                "klein_double_block" => bench_flame(
                    || { let _ = run_klein_double_block(&ts)?; Ok(()) }, 3, 10,
                ),
                _ => return None,
            })
        }

        // conv2d left unwired (needs Conv2d wrapper); pattern/sdpa_backward
        // left unwired (needs autograd + backward harness).
        _ => None,
    }
}

#[test]
#[ignore]
fn perf_comparison() {
    if skip_if_no_fixtures() { return; }

    let timing_path = fixtures_dir().join("timing_results.json");
    if !timing_path.exists() {
        println!("No timing_results.json found — skipping perf comparison");
        return;
    }

    let timing_json: Vec<serde_json::Value> = {
        let data = fs::read_to_string(&timing_path).unwrap();
        serde_json::from_str(&data).unwrap()
    };

    println!();
    println!(
        "{:<35} {:<28} {:>12} {:>12} {:>10}",
        "op", "shape", "PyTorch µs", "flame µs", "ratio"
    );
    println!("{}", "-".repeat(100));

    for entry in &timing_json {
        let op = entry["op"].as_str().unwrap_or("");
        let shape_name = entry["shape_name"].as_str().unwrap_or("");
        let pytorch_us = entry["median_us"].as_f64().unwrap_or(0.0);

        let flame_us = bench_flame_for(op, shape_name).unwrap_or(0.0);

        let ratio = if pytorch_us > 0.0 && flame_us > 0.0 {
            format!("{:.2}x", flame_us / pytorch_us)
        } else {
            "—".to_string()
        };

        println!(
            "{:<35} {:<28} {:>12.1} {:>12.1} {:>10}",
            op, shape_name, pytorch_us, flame_us, ratio
        );
    }
}
